// LESSON: Reference Page 1 - Interface och kontrakt.
// You will learn: Define contracts, implement interfaces, and program to abstractions.
class Prog2Reference426 {
  // EXEMPEL 1: Ett interface sager vilka metoder en klass lovar att ha.
  interface Measurable {
    double measure();
  }
  static class Box implements Measurable {
    private final double width;
    private final double height;
    Box(double width, double height) { this.width = width; this.height = height; }
    public double measure() { return width * height; }
  }
  // EXEMPEL 2: En klass kan implementera flera interface.
  interface Named {
    String name();
  }
  interface Priced {
    int priceInOre();
  }
  static class Ticket implements Named, Priced {
    public String name() { return "Ticket"; }
    public int priceInOre() { return 8000; }
  }
  // EXEMPEL 3: Programmera mot interface nar implementationen kan bytas.
  static int total(java.util.List<Priced> items) {
    int sum = 0;
    for (Priced item : items) { sum += item.priceInOre(); }
    return sum;
  }
}
